'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AlertCircle, Loader2 } from 'lucide-react';
import { Message } from './Message';
import { ChatInput } from './ChatInput';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Message as MessageType } from '@/lib/types';
import { chatService } from '@/services/chat.service';
import { cn } from '@/lib/utils/cn';

interface ChatContainerProps {
  sessionId?: string;
  className?: string;
}

const SUGGESTIONS = [
  'What are the recent amendments to the Indian Penal Code?',
  'Explain Article 21 of the Constitution',
  'What is the procedure for filing a PIL?',
  'Rights of an arrested person in India',
  'Difference between bail and anticipatory bail',
];

export function ChatContainer({ sessionId: initialSessionId, className }: ChatContainerProps) {
  const [messages, setMessages] = useState<MessageType[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [sessionId, setSessionId] = useState<string | undefined>(initialSessionId);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const scrollAreaRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // Load chat history if sessionId exists
  useEffect(() => {
    if (sessionId) {
      loadChatHistory();
    }
  }, [sessionId]);

  const loadChatHistory = async () => {
    if (!sessionId) return;
    
    try {
      const history = await chatService.getChatHistory(sessionId);
      setMessages(history);
    } catch (err) {
      console.error('Failed to load chat history:', err);
      setError('Failed to load chat history');
    }
  };

  const handleSendMessage = async (content: string) => {
    setError(null);
    
    // Create user message
    const userMessage: MessageType = {
      id: `temp-${Date.now()}`,
      role: 'user',
      content,
      timestamp: new Date(),
    };
    
    setMessages((prev) => [...prev, userMessage]);
    setIsLoading(true);
    setIsTyping(true);

    try {
      // Create session if needed
      if (!sessionId) {
        const session = await chatService.createSession();
        setSessionId(session.id);
      }

      // Create temporary assistant message for typing indicator
      const tempAssistantMessage: MessageType = {
        id: `temp-assistant-${Date.now()}`,
        role: 'assistant',
        content: '',
        timestamp: new Date(),
      };
      
      setMessages((prev) => [...prev, tempAssistantMessage]);

      // Stream the response
      let fullContent = '';
      const startTime = Date.now();
      
      for await (const chunk of chatService.streamMessage(content, sessionId)) {
        fullContent += chunk;
        
        // Update the temporary message with accumulated content
        setMessages((prev) => 
          prev.map((msg) => 
            msg.id === tempAssistantMessage.id
              ? { ...msg, content: fullContent }
              : msg
          )
        );
      }
      
      // Final update with metadata
      const processingTime = Date.now() - startTime;
      
      setMessages((prev) => 
        prev.map((msg) => 
          msg.id === tempAssistantMessage.id
            ? {
                ...msg,
                id: `msg-${Date.now()}`, // Replace with real ID from backend
                metadata: {
                  processingTime,
                  // Sources would be populated from the backend response
                  sources: [],
                },
              }
            : msg
        )
      );
    } catch (err) {
      console.error('Failed to send message:', err);
      setError('Failed to send message. Please try again.');
      
      // Remove the typing message on error
      setMessages((prev) => prev.filter((msg) => !msg.id.startsWith('temp-assistant')));
    } finally {
      setIsLoading(false);
      setIsTyping(false);
    }
  };

  const handleNewChat = () => {
    setMessages([]);
    setSessionId(undefined);
    setError(null);
  };

  return (
    <div className={cn('flex h-full flex-col', className)}>
      {/* Header */}
      <div className="flex items-center justify-between border-b border-neutral-200 px-6 py-4 dark:border-neutral-800">
        <div>
          <h2 className="text-lg font-semibold">Legal Assistant</h2>
          <p className="text-sm text-neutral-600 dark:text-neutral-400">
            AI-powered Indian law consultation
          </p>
        </div>
        <Button variant="outline" size="sm" onClick={handleNewChat}>
          New Chat
        </Button>
      </div>

      {/* Messages Area */}
      <div
        ref={scrollAreaRef}
        className="flex-1 overflow-y-auto"
      >
        {messages.length === 0 ? (
          <div className="flex h-full items-center justify-center p-8">
            <Card variant="glass" className="max-w-2xl text-center">
              <div className="space-y-4">
                <div className="mx-auto h-16 w-16 rounded-full bg-gradient-to-br from-primary-500 to-secondary-500 p-3">
                  <Loader2 className="h-full w-full text-white" />
                </div>
                <div>
                  <h3 className="text-xl font-semibold">Welcome to Your Legal Assistant</h3>
                  <p className="mt-2 text-sm text-neutral-600 dark:text-neutral-400">
                    I can help you understand Indian law, find relevant cases, and guide you through legal procedures.
                    All information is sourced from official legal databases.
                  </p>
                </div>
                <div className="flex flex-wrap justify-center gap-2">
                  {SUGGESTIONS.slice(0, 3).map((suggestion, index) => (
                    <Button
                      key={index}
                      variant="outline"
                      size="sm"
                      onClick={() => handleSendMessage(suggestion)}
                    >
                      {suggestion}
                    </Button>
                  ))}
                </div>
              </div>
            </Card>
          </div>
        ) : (
          <div className="pb-4">
            <AnimatePresence>
              {messages.map((message, index) => (
                <Message
                  key={message.id}
                  message={message}
                  isTyping={isTyping && index === messages.length - 1 && message.role === 'assistant' && !message.content}
                />
              ))}
            </AnimatePresence>
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>

      {/* Error Display */}
      <AnimatePresence>
        {error && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 10 }}
            className="mx-4 mb-2"
          >
            <Card variant="bordered" className="border-red-200 bg-red-50 dark:border-red-900 dark:bg-red-950">
              <div className="flex items-center gap-2 text-sm text-red-700 dark:text-red-300">
                <AlertCircle className="h-4 w-4" />
                <span>{error}</span>
              </div>
            </Card>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Input Area */}
      <div className="border-t border-neutral-200 p-4 dark:border-neutral-800">
        <ChatInput
          onSendMessage={handleSendMessage}
          isLoading={isLoading}
          suggestions={SUGGESTIONS}
        />
      </div>
    </div>
  );
} 