'use client';

import React from 'react';
import { motion } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { BookOpen, FileText, Gavel, ScrollText, User, Bot } from 'lucide-react';
import { Message as MessageType, LegalSource } from '@/lib/types';
import { cn } from '@/lib/utils/cn';
import { Card } from '@/components/ui/Card';

interface MessageProps {
  message: MessageType;
  isTyping?: boolean;
}

const sourceIcons: Record<LegalSource['type'], React.ReactNode> = {
  case_law: <Gavel className="h-4 w-4" />,
  statute: <BookOpen className="h-4 w-4" />,
  regulation: <FileText className="h-4 w-4" />,
  policy: <ScrollText className="h-4 w-4" />,
};

export function Message({ message, isTyping = false }: MessageProps) {
  const isUser = message.role === 'user';

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className={cn(
        'flex gap-3 px-4 py-6',
        isUser ? 'flex-row-reverse' : 'flex-row'
      )}
    >
      {/* Avatar */}
      <div
        className={cn(
          'flex h-10 w-10 shrink-0 items-center justify-center rounded-full',
          isUser
            ? 'bg-primary-100 text-primary-700 dark:bg-primary-900 dark:text-primary-300'
            : 'bg-secondary-100 text-secondary-700 dark:bg-secondary-900 dark:text-secondary-300'
        )}
      >
        {isUser ? <User className="h-5 w-5" /> : <Bot className="h-5 w-5" />}
      </div>

      {/* Message Content */}
      <div className={cn('flex max-w-[70%] flex-col gap-2', isUser && 'items-end')}>
        <Card
          variant={isUser ? 'default' : 'glass'}
          className={cn(
            'relative overflow-hidden',
            isUser && 'bg-primary-50 dark:bg-primary-950'
          )}
        >
          {isTyping ? (
            <div className="flex items-center gap-2">
              <span className="h-2 w-2 animate-bounce rounded-full bg-secondary-600 [animation-delay:-0.3s]" />
              <span className="h-2 w-2 animate-bounce rounded-full bg-secondary-600 [animation-delay:-0.15s]" />
              <span className="h-2 w-2 animate-bounce rounded-full bg-secondary-600" />
            </div>
          ) : (
            <div className="prose prose-sm dark:prose-invert max-w-none">
              <ReactMarkdown remarkPlugins={[remarkGfm]}>
                {message.content}
              </ReactMarkdown>
            </div>
          )}
        </Card>

        {/* Legal Sources */}
        {message.metadata?.sources && message.metadata.sources.length > 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.2 }}
            className="flex flex-wrap gap-2"
          >
            {message.metadata.sources.map((source) => (
              <button
                key={source.id}
                className="flex items-center gap-1.5 rounded-full bg-neutral-100 px-3 py-1 text-xs font-medium text-neutral-700 transition-colors hover:bg-neutral-200 dark:bg-neutral-800 dark:text-neutral-300 dark:hover:bg-neutral-700"
                onClick={() => {
                  // Handle source click - could open a modal or navigate
                  console.log('Source clicked:', source);
                }}
              >
                {sourceIcons[source.type]}
                <span>{source.citation}</span>
                <span className="text-neutral-500">
                  ({Math.round(source.relevanceScore * 100)}%)
                </span>
              </button>
            ))}
          </motion.div>
        )}

        {/* Metadata */}
        <div className="flex items-center gap-2 text-xs text-neutral-500 dark:text-neutral-400">
          <time dateTime={message.timestamp.toISOString()}>
            {new Date(message.timestamp).toLocaleTimeString('en-IN', {
              hour: '2-digit',
              minute: '2-digit',
            })}
          </time>
          {message.metadata?.processingTime && (
            <>
              <span>•</span>
              <span>{message.metadata.processingTime}ms</span>
            </>
          )}
        </div>
      </div>
    </motion.div>
  );
}